try:
    result = _parse_annotation('Tuple[int, str]')
    print('Result:', result)
except Exception as e:
    print('Error:', type(e).__name__, str(e))

# Test with single element tuple
try:
    result = _parse_annotation('Tuple[int]')
    print('Result:', result)
except Exception as e:
    print('Error:', type(e).__name__, str(e))
